      "scores_json": "{\"data_strength\": 3, \"signal_recency\": 6.7, \"signal_convergence\": 3, \"capability_fit\": 8.3, \"engagement_size\": 10, \"strategic_value\": 5, \"political_alignment\": 7, \"budget_availability\": 6, \"timing\": 6, \"competitive_landscape\": 5}",
